mapper.sql:
FROM sys_user su
INNER JOIN sys_user_info sui ON su.id = sui.user_id AND sui.enabled = '1'
INNER JOIN sys_user_role sur ON su.id = sur.user_id AND sur.enabled = '1'
INNER JOIN sys_role sr ON sur.role_id = sr.id AND sr.enabled = '1'
INNER JOIN sys_user_dept sud ON su.id = sud.user_id AND sud.enabled = '1'
INNER JOIN sys_dept sd ON sud.dept_id = sd.id AND sd.enabled = '1'
WHERE su.enabled = '1'

    AND su.username LIKE CONCAT(#{req.username},'%')


    AND su.nickname LIKE CONCAT(#{req.nickname},'%')


    AND su.data_status = #{req.dataStatus}


    AND su.create_time BETWEEN #{req.startTime} AND #{req.endTime}


    AND su.id != #{req.superAdminId}


    AND sui.user_type = #{req.userType}


    AND sui.telephone = #{req.telephone}


    ${req.dataScopeSql}

GROUP BY su.id
ORDER BY su.id DESC

FROM sys_user t LEFT JOIN (SELECT su.id, (SELECT LISTAGG(dept_name, ', ') WITHIN GROUP (ORDER BY dept_name) FROM (SELECT DISTINCT sud.user_id, dept_name FROM sys_dept sd, sys_user_dept sud WHERE sd.id = sud.dept_id AND sud.enabled = '1' AND sd.enabled = '1') ta WHERE ta.user_id = su.id GROUP BY ta.user_id) AS dept_names, (SELECT LISTAGG(role_name, ', ') WITHIN GROUP (ORDER BY role_name) FROM (SELECT DISTINCT sur.user_id, sr.role_name FROM sys_role sr, sys_user_role sur WHERE sr.id = sur.role_id AND sur.enabled = '1' AND sr.enabled = '1') tb WHERE tb.user_id = su.id GROUP BY tb.user_id) AS role_names FROM sys_user su WHERE su.enabled = '1'
AND su.username LIKE CONCAT(#{req.username},'%')
AND su.nickname LIKE CONCAT(#{req.nickname},'%')
AND su.telephone LIKE CONCAT(#{req.telephone},'%')
AND su.data_status = #{req.dataStatus}
AND su.create_time BETWEEN #{req.startTime} AND #{req.endTime}
AND su.id != #{req.superAdminId}
${req.dataScopeSql}
GROUP BY su.id) t1 ON t.id = t1.id ORDER BY t.id DESC
